#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;
typedef pair<int,int> pii;

const int N=1e5+10,mod=1e8-3;

int n,p[N],c[N],ans;
pii a[N],b[N];

void add(int x,int k){
    for(;x<=n;x+=(x&(-x)))
        c[x]+=k;
}

int ask(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=c[x];
    return res;
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i].x);
        a[i].y=i;
    }
    for(int i=1;i<=n;i++){
        scanf("%d",&b[i].x);
        b[i].y=i;
    }
    sort(a+1,a+n+1);
    sort(b+1,b+n+1);
    for(int i=1;i<=n;i++)
        p[a[i].y]=b[i].y;
    for(int i=1;i<=n;i++){
        add(p[i],1);
        ans=(ans+i-ask(p[i]))%mod;
    }
    printf("%d",ans);
    return 0;
}
